content:
# how many cpus will be init
cpus ?= 2
cmake-flags := -DCPUS=$(cpus)

# platform: qemu, visionfive
platform ?= qemu

# target:
# - tests(测试syscall)
# - bin(终端)
# - comp(比赛内容, 须复制sdcard.img 到image目录下并更名为comp.img)
# - busybox(busybox终端)
# - final(决赛内容)
target ?= final

# filesystem: 镜像所用的文件系统，支持 fat32 和 ext4
filesystem ?= ext4

cmake-flags += -DUSER_TARGET=$(target)

include init.mk
all:mod gen_syscall build dump 
.PHONY:build 

sdcard: make-image mod gen_syscall build dump
	@riscv64-unknown-elf-objcopy bin/kernel -O binary --strip-all bin/kernel.bin
	@dd if=/dev/zero of=image/sdcard.img bs=1M count=768
	@mkfs.ext4 -F -b 4096 -L rootfs image/sdcard.img
	@sudo mount -t ext4 image/sdcard.img data/mnt
	@sudo cp bin/kernel.bin data/mnt/
	@sync data/mnt/
	@sudo umount -v data/mnt
.PHONY: build

run: make-image gen_syscall build
	sh scripts/qemu.sh $(cpus) $(target)
.PHONY: build

run_final:gen_syscall build
	sh scripts/qemu.sh $(cpus) $(target)
.PHONY: build

debug:gen_syscall build-debug dump
	@sh scripts/qemu-gdb.sh $(cpus) $(target)
.PHONY: build-debug

gdb-client:
	riscv64-unknown-elf-gdb -quiet -ex "set architecture riscv:rv64" -ex "target remote localhost:26000" kernel-qemu

build:
	$(call build_hustOS,Release)

build-debug:
	$(call build_hustOS,Debug)

build-minsize:
	$(call build_hustOS,MinsizeRel)

# to genanerate binary files(asm, sym)
dump:
	@sh scripts/objdump-files.sh

make-image:
	$(call build_image,$(target))

# clean build files
clean:
	@echo "Cleaning hustOS"
	@if [ -d "build" ]; then rm -r build; fi
	@if [ -d "bin" ]; then rm -r bin; fi
	@if [ -d "data" ]; then rm -r data; fi
	@if [ -d "objdump-files" ]; then rm -rf objdump-files; fi
	@if [ -f "kernel-qemu" ]; then rm kernel-qemu; fi
	@if [ -f "sbi-qemu" ]; then rm sbi-qemu; fi
	@if [ -d "image" ]; then rm -r image; fi
	@if [ -d "kernel/dep/sdcard/target" ]; then rm -r kernel/dep/sdcard/target; fi
	@echo "Done"

mod:
	@chmod +x tool/xxd

gen_syscall: tool/syscall.tbl
	@python3 tool/gen_syscall.py
	@mv sysdef.h include/syscall/sysdef.h
	@mv sysnum.h include/syscall/sysnum.h
	@mv syscall.h include/syscall/syscall.h
	@mv syscall_table.c kernel/src/syscall/syscall_table.c

format:
	find ./include ./kernel ./user -name '*.h' -or -name '*.c' | xargs clang-format -i

message(STATUS "Building kernel under ${CMAKE_CURRENT_SOURCE_DIR} target=${USER_TARGET}")

add_custom_command(
        OUTPUT ${CMAKE_CURRENT_SOURCE_DIR}/asm/sddata.S
        COMMAND ${CMAKE_CURRENT_SOURCE_DIR}/asm/gen_sddata.sh ${CMAKE_CURRENT_SOURCE_DIR}/../../image/${USER_TARGET}.img ${CMAKE_CURRENT_SOURCE_DIR}/asm
        DEPENDS ${CMAKE_CURRENT_SOURCE_DIR}/../../image/${USER_TARGET}.img
        COMMENT "Generating sddata.S"
        VERBATIM
)

add_subdirectory(asm)
add_subdirectory(atomic)
add_subdirectory(driver)
add_subdirectory(fs)
add_subdirectory(kernel)
add_subdirectory(lib)
add_subdirectory(mm)
add_subdirectory(proc)
add_subdirectory(syscall)
add_subdirectory(ipc)
set(SOURCES
        ${asm_sources}
        ${atomic_sources}
        ${driver_sources}
        ${fs_sources}
        ${kernel_sources}
        ${lib_sources}
        ${mm_sources}
        ${proc_sources}
        ${syscall_sources}
        ${ipc_sources}
)

set (PLATFORM_KERNELLIB ${PLATFORM})
string(TOUPPER ${PLATFORM_KERNELLIB} PLATFORM_KERNELLIB)

add_library(kernel_lib ${SOURCES})
target_compile_options(kernel_lib PRIVATE -D${PLATFORM_KERNELLIB})
add_dependencies(kernel_lib initcode)
if (${PLATFORM_KERNELLIB} STREQUAL "VISIONFIVE")
        target_link_libraries(kernel_lib PRIVATE sd_driver_lib)
endif()

#include "riscv.h"

void main();

// entry.S needs one stack per CPU.
// Per-CPU state
__attribute__((aligned(16))) char stack0[NCPU][4096];

// entry.S jumps here in machine mode on stack0.
void start(long hartid, uint64 _dtb_entry) {
    w_tp(hartid);
    main();
}

#include "main.h"
#include <fs/bio.h>
#include "atomic/spinlock.h"
#include "kernel/cpu.h"
#include "proc/sched.h"
volatile int started = 0;
volatile int first = 0;
// start() jumps here in supervisor mode on all CPUs.
void main() {
    if (atomic_read4((int *) &first) == 0) {
        first = 1;
        hartids[cpuid()] = 1;
        console_init();
        null_zero_dev_init();
        printf_init();
        hartinit();
        printf("\nCabbageOS kernel is booting\n\n");
        mm_init();
        vmas_init();
        // KVM
        kvm_init(); // create kernel page table
        kvm_init_hart(); // turn on paging
        // Proc management
        proc_init(); // process table
        tcb_init();
        // Timer
        timer_init();
        // Trap
        trap_init(); // trap vectors
        trap_init_hart(); // install kernel trap vector
        // PLIC
        plic_init(); // set up interrupt controller
        plic_init_hart(); // ask PLIC for device interrupts
        // File System
        b_init(); // buffer cache
        file_init();
        inode_table_init();
        vfs_ext_init(); // ext4

        // fat32
        // fat32_fat_entry_init();

        // futex hash table
        futex_hash_init();

        vfs_ext_init(); // ext4
        // virtual disk
        // virtio_disk_init(); // emulated hard disk
        disk_init(); // emulated hard disk
        // First user process
        comp_init();
        //    user_init(); // first user process
        __sync_synchronize();
        started = 1;
        __sync_synchronize();
        start_all_harts();
    } else {
        while (atomic_read4((int *) &started) == 0)
            ;
        __sync_synchronize();
        hartinit();
        kvm_init_hart(); // turn on paging
        trap_init_hart(); // install kernel trap vector
        plic_init_hart(); // ask PLIC for device interrupts
    }

    thread_scheduler();
}

OUTPUT_ARCH( "riscv" )
ENTRY( _entry )

SECTIONS
{
  /*
   * ensure that entry.S / _entry is at 0x80000000,
   * where qemu's -kernel jumps.
   */
  . = 0x80200000;

  .text : {
    *(.text .text.*)
    . = ALIGN(0x1000);
    _trampoline = .;
    *(trampsec)
    . = ALIGN(0x1000);
    ASSERT(. - _trampoline == 0x1000, "error: trampoline larger than one page");
    _sigreturn = .;
    *(sigret_sec)
    . = ALIGN(0x1000);
    ASSERT(. - _sigreturn == 0x1000, "error: sigreturn larger than one page");
    PROVIDE(etext = .);
  }

  .rodata : {
    . = ALIGN(16);
    *(.srodata .srodata.*) /* do not need to distinguish this from .rodata */
    . = ALIGN(16);
    *(.rodata .rodata.*)
  }

  .data : {
    . = ALIGN(16);
    *(.sdata .sdata.*) /* do not need to distinguish this from .data */
    . = ALIGN(16);
    *(.stack)
    . = ALIGN(16);
    *(.data .data.*)
  }

  .bss : {
    . = ALIGN(16);
    PROVIDE(bss_start = .); 
    *(.sbss .sbss.*) /* do not need to distinguish this from .bss */
    . = ALIGN(16);
    *(.bss .bss.*)
    PROVIDE(bss_end = .); 
  }

  PROVIDE(end = .);
}

