// Return the address of the PTE in page table pagetable
// that corresponds to virtual address va.  If alloc!=0,
// create any required page-table pages.
//
// The risc-v Sv39 scheme has three levels of page-table
// pages. A page-table page contains 512 64-bit PTEs.
// A 64-bit virtual address is split into five fields:
//   39..63 -- must be zero.
//   30..38 -- 9 bits of level-2 index.
//   21..29 -- 9 bits of level-1 index.
//   12..20 -- 9 bits of level-0 index.
//    0..11 -- 12 bits of byte offset within the page.
#define LEVELS 3
/* return the leaf pte's level, set (pte_t *)*pte to this pte's address at the same time */
int walk(pagetable_t pagetable, uint64 va, int alloc, int low_level, pte_t **pte) {
    if (va >= MAXVA)
        panic("walk");

    for (int level = LEVELS - 1; level > low_level; level--) {
        pte_t *pte_tmp = &pagetable[PN(level, va)];
        if (*pte_tmp & PTE_V) {
            // find a superpage leaf PTE
            if ((*pte_tmp & PTE_R) || (*pte_tmp & PTE_X)) {
                *pte = pte_tmp;
                /* assert: only support 2MB leaf-pte */
                ASSERT(level == 1);
                return level;
            }
            pagetable = (pagetable_t) PTE2PA(*pte_tmp);
        } else {
            if (!alloc || (pagetable = (pde_t *) kzalloc(PGSIZE)) == 0) {
                *pte = 0;
                return -1;
            }
            *pte_tmp = PA2PTE(pagetable) | PTE_V;
        }
    }
    *pte = (pte_t *) &pagetable[PN(low_level, va)];
    return 0;
}

/* since the kernel only has direct mapping, add this func to make things easy
 * getphyaddr will return the physical address of the va
 * return 0 if the va is not in the pagetable
 */
paddr_t get_phyaddr(pagetable_t pagetable, vaddr_t va) {
    const vaddr_t aligned_va = PGROUNDDOWN(va);
    const paddr_t aligned_pa = walk_addr(pagetable, va);
    if (aligned_pa == 0) {
        return 0;
    }
    return aligned_pa + (va - aligned_va);
}

// Look up a virtual address, return the physical address,
// or 0 if not mapped.
// Can only be used to look up user pages.
uint64 walk_addr(pagetable_t pagetable, uint64 va) {
    pte_t *pte;

    if (va >= MAXVA)
        return 0;

    const int level = walk(pagetable, va, 0, 0, &pte);
    ASSERT(level <= 1);
    if (pte == 0 || (*pte & PTE_V) == 0 || (*pte & PTE_U) == 0)
        return 0;
    const uint64 pa = PTE2PA(*pte);
    if (level == COMMONPAGE) {
        return pa;
    }
    if (level == SUPERPAGE) {
        return pa + (PGROUNDDOWN(va) - SUPERPG_DOWN(va));
    }
    panic("can not reach here");
}

