static uint32 perm_vma2pte(uint32 vma_perm) {
    uint32 pte_perm = 0;
    if (perm_readable(vma_perm)) {
        pte_perm |= PTE_R;
    }
    if (perm_writable(vma_perm)) {
        pte_perm |= PTE_W;
    }
    if (perm_executable(vma_perm)) {
        pte_perm |= PTE_X;
    }
    return pte_perm;
}

int page_fault(uint64 cause, pagetable_t pagetable, vaddr_t st_val) {
    /* the va exceed the MAXVA is illegal */
    if (PGROUNDDOWN(st_val) >= MAXVA) {
        printf("exceed the MAXVA");
        return -1;
    }
    const struct vma *vma = find_vma_for_va(proc_current()->mm, st_val);
    if (vma != NULL) {
        if (!CHECK_PERM(cause, vma)) {
            PAGEFAULT("permission checked failed");
            return -1;
        }
        // printfMAGENTA("page fault: cause: %p, sepc: %p, va: %p, vma: %p\n", cause, r_sepc(), st_val, vma);
        // printfMAGENTA("current vma: %#p-%#p, file:%p\n", vma->startva, vma->startva + vma->size, vma->vm_file);
        // print_vma(&proc_current()->mm->head_vma);
        pte_t *pte;
        const int level = walk(pagetable, st_val, 0, 0, &pte);
        if (pte == NULL || (*pte == 0)) {
            uvm_alloc(pagetable, PGROUNDDOWN(st_val), PGROUNDUP(st_val + 1), perm_vma2pte(vma->perm));
            if (vma->type == VMA_FILE) {
                const paddr_t pa = walk_addr(pagetable, st_val);
                struct inode *f_inode;
                if (vma->vm_file->f_type == FAT32)
                    f_inode = vma->vm_file->f_data.f_vnode->data;
                else
                    f_inode = vfs_ext_namei(vma->vm_file->f_data.f_vnode->path);
                if (!f_inode) {
                    printfMAGENTA("page fault: cause: %p, sepc: %p, va: %p, vma: %p\n", cause, r_sepc(), st_val, vma);
                    printfMAGENTA("current vma: %#p-%#p, file:%p\n", vma->startva, vma->startva + vma->size, vma->vm_file);
                }
                f_inode->i_op->lock(f_inode);
                f_inode->i_op->read(f_inode, 0, pa, vma->offset + PGROUNDDOWN(st_val) - vma->startva, PGSIZE);
                f_inode->i_op->unlock(f_inode);
            }
        } else {
            const uint64 pa = PTE2PA(*pte);
            const uint flags = PTE_FLAGS(*pte);
            ASSERT(flags & PTE_V);
            // vm_print(proc_current()->mm->pagetable, 1, 0, 0, 0);
            /* copy-on-write handler */
            if (is_a_cow_page(flags)) {
                return cow(pte, level, pa, flags);
            }
            return -1;
        }

    } else {
        PAGEFAULT("va is not in the vmas");
        printf("va: %p\n", st_val);
        print_vma(&proc_current()->mm->head_vma);
        return -1;
    }

    return 0;
}
int is_a_cow_page(const int flags) {
    /* write to an unshared page is illegal */
    if ((flags & PTE_SHARE) == 0) {
        PAGEFAULT("cow: try to write a readonly page");
        return 0;
    }

    /* write to readonly shared page is illegal */
    if ((flags & PTE_READONLY) > 0) {
        PAGEFAULT("cow: try to write a readonly shared page");
        return 0;
    }
    return 1;
}
int cow(pte_t *pte, const int level, const paddr_t pa, const int flags) {
    void *mem;
    if (level == SUPERPAGE) {
        // 2MB superpage
        if ((mem = kmalloc(SUPERPGSIZE)) == 0) {
            return -1;
        }
        memmove(mem, (void *) pa, SUPERPGSIZE);
    } else if (level == COMMONPAGE) {
        // common page
        if ((mem = kmalloc(PGSIZE)) == 0) {
            return -1;
        }
        memmove(mem, (void *) pa, PGSIZE);
    } else {
        PAGEFAULT("the level of leaf pte is wrong");
        return -1;
    }

    *pte = PA2PTE((uint64) mem) | flags | PTE_W;
    kfree((void *) pa);
    return 0;
}

