void deleteChild(struct proc *parent, struct proc *child) {
    if (nosibling(child)) {
        parent->first_child = NULL;
    } else {
        struct proc *first_child = firstchild(parent);
        if (child == first_child) {
            parent->first_child = nextsibling(first_child);
        }
        list_del_reinit(&child->sibling_list);
    }
}

void appendChild(struct proc *parent, struct proc *child) {
    if (nochildren(parent)) {
        parent->first_child = child;
    } else {
        list_add_tail(&child->sibling_list, &(firstchild(parent)->sibling_list));
    }
}


// Return the current struct tcb *, or zero if none.
struct proc *proc_current(void) { return thread_current()->p; }

// allocate a new proc (return with lock)
struct proc *alloc_proc(void) {
    struct proc *p;
    // fetch an unused proc from unused queue
    // fetch an unused thread from unused queue as its group leader
    p = (struct proc *) Queue_provide_atomic(&unused_p_q, 1);
    if (p == NULL)
        return 0;

    acquire(&p->lock); // return with lock

    p->pid = alloc_pid;
    cnt_pid_inc; // increase the count of pid

    // state
    PCB_Q_changeState(p, PCB_USED);

    // proc family
    p->first_child = NULL;
    INIT_LIST_HEAD(&p->sibling_list);

    // thread group (list head) sets to NULL
    if ((p->tg = (struct thread_group *) kalloc()) == 0) {
        free_proc(p);
        release(&p->lock);
        return 0;
    }
    thread_group_init(p->tg);

    // ipc namespace
    if ((p->ipc_ns = (struct ipc_namespace *) kalloc()) == 0) {
        free_proc(p);
        release(&p->lock);
        return 0;
    }

    // shared memory
    shm_init_ns(p->ipc_ns);
    INIT_LIST_HEAD(&p->sysvshm.shm_clist);
    // for prlimit
    proc_prlimit_init(p);


    p->mm = alloc_mm();
    if (p->mm == 0) {
        free_proc(p);
        release(&p->lock);
        return 0;
    }
    INIT_LIST_HEAD(&p->mm->head_vma);

    // for setitimer
    p->real_timer.expires = 0;
    p->real_timer.interval = 0;
    INIT_LIST_HEAD(&p->real_timer.list);

    // semaphore for waitpid
    sem_init(&p->sem_wait_chan_parent, 0, "wait_parent");
    sem_init(&p->sem_wait_chan_self, 0, "wait_self");

    return p;
}

// create a proc with a group leader thread
struct proc *create_proc() {
    struct tcb *t = NULL;
    struct proc *p = NULL;
    if ((p = alloc_proc()) == 0) {
        return 0;
    }
    if ((t = alloc_thread(thread_forkret)) == 0) {
        free_proc(p);
        return 0;
    }

    proc_join_thread(p, t, NULL);


    release(&t->lock);

    return p;
}

// free a existed proc
void free_proc(struct proc *p) {
    if (p->mm)
        free_mm(p->mm, p->tg->thread_idx);
    p->mm = 0;
    if (p->tg)
        kfree((void *) p->tg);
    p->tg = 0;
    if (p->ipc_ns) {
        if (shm_ids(p->ipc_ns).key_ht) {
            struct hash_table *table = shm_ids(p->ipc_ns).key_ht;
            acquire(&table->lock);
            for (uint64 i = 0; i < table->size; i++) {
                struct kern_ipc_perm *pos, *n;
                list_for_each_entry_safe(pos, n, &table->hash_head[i].list, ipc_hash_node) { kfree(pos); }
            }
            release(&table->lock);
            kfree(table);
        }
        kfree((void *) p->ipc_ns);
    }
    p->ipc_ns = 0;
    if (!list_empty(&p->sysvshm.shm_clist)) {
        struct shmid_kernel *shmid_cur = NULL;
        struct shmid_kernel *shmid_tmp = NULL;
        list_for_each_entry_safe(shmid_cur, shmid_tmp, &p->sysvshm.shm_clist, shm_clist) {
            kfree(shmid_cur->shm_file->private_data);
            kfree(shmid_cur);
        }
    }
    p->pid = 0;
    p->parent = 0;
    p->name[0] = 0;
    p->killed = 0;
    p->exit_stat = 0;

    PCB_Q_changeState(p, PCB_UNUSED);
}

