    struct tcb *t = NULL;
    for (int i = 0; i < NTCB; i++) {
        t = thread + i;
        acquire(&t->lock);
        if (t->tid == tid) {
            release(&t->lock);
            return t;
        }
        release(&t->lock);
    }
    return NULL;
