// Allocate a page for each process's kernel stack.
// Map it high in memory, followed by an invalid
// guard page.

void tcb_mapstacks(pagetable_t kpgtbl) {
    struct tcb *t;

    for (t = thread; t < &thread[NTCB]; t++) {
        char *pa = kalloc();
        if (pa == 0)
            panic("kalloc");
        uint64 va = KSTACK((int) (t - thread));
        kvm_map(kpgtbl, va, (uint64) pa, PGSIZE, PTE_R | PTE_W, COMMONPAGE);
    }
}

// Create a user page table for a given process, with no user memory,
// but with trampoline and trapframe pages.
pagetable_t proc_pagetable() {
    pagetable_t page_table;
    page_table = uvm_create();
    if (page_table == 0)
        return 0;
    if (map_pages(page_table, TRAMPOLINE, PGSIZE, (uint64) trampoline, PTE_R | PTE_X, 0) < 0) {
        free_walk(page_table);
        return 0;
    }

    /* map with PTE_U */
    if (map_pages(page_table, SIGRETURN, PGSIZE, (uint64)__user_rt_sigreturn, PTE_R | PTE_X | PTE_U, 0) < 0) {
        uvm_unmap(page_table, TRAMPOLINE, 1, 0, 0);
        free_walk(page_table);
        return 0;
    }

    return page_table;
}

int thread_trapframe(struct tcb *t, int still) {
    struct proc *p = t->p;
    int offset;

    // starts from 0
    if (still)
        offset = t->tidx;
    else
        offset = p->tg->thread_idx++;

    if (p == NULL)
        return -1;
    pagetable_t pagetable = p->mm->pagetable;

    if (map_pages(pagetable, TRAPFRAME - offset * PGSIZE, PGSIZE, (uint64) (t->trapframe), PTE_R | PTE_W, 0) < 0) {
        if (offset == 0) {
            uvm_unmap(pagetable, TRAMPOLINE, 1, 0, 0);
            uvm_free(p->mm);
        }
        return 0;
    }
    return 1;
}

// Free a process's page table, and free the
// physical memory it refers to.
void proc_free_pagetable(mm_ptr_t mm, int thread_idx) {
    // max_offset starts from 0
    uvm_unmap(mm->pagetable, TRAMPOLINE, 1, 0, 0);
    uvm_unmap(mm->pagetable, SIGRETURN, 1, 0, 0);
    uvm_unmap(mm->pagetable, USTACK_GURAD_PAGE, 1, 0, 1);
    acquire(&mm->lock);
    for (int offset = 0; offset < thread_idx; offset++) {
        uvm_unmap(mm->pagetable, TRAPFRAME - offset * PGSIZE, 1, 0, 1);
    }
    release(&mm->lock);
    uvm_free(mm);
}

// Grow or shrink user memory by n bytes.
// Return 0 on success, -1 on failure.
int grow_heap(int n) {
    uint64 oldsz, newsz, sz;
    struct proc *p = proc_current();

    sz = p->mm->brk;
    oldsz = p->mm->brk;
    newsz = p->mm->brk + n;
    if (newsz < p->mm->start_brk) {
        Info("grow_heap: newsz < start_brk");
        do_exit(-1);
    }

    if (n > 0) {
        pte_t *pte;
        int level = walk(p->mm->pagetable, oldsz, 0, 0, &pte);
        if (pte == NULL && level != -1) {
            panic("grow_proc: wrong");
        }
        ASSERT(level <= 1);
        if (level == COMMONPAGE) {
            if (PGROUNDUP(oldsz) >= newsz) {
                p->mm->brk = newsz;
                return 0;
            }
        } else if (level == SUPERPAGE) {
            if (SUPERPG_ROUNDUP(oldsz) >= newsz) {
                p->mm->brk = newsz;
                return 0;
            }
        } else if (level != -1) {
            panic("grow_proc: wrong level");
        }

        if ((sz = uvm_alloc(p->mm->pagetable, oldsz, newsz, PTE_W | PTE_R)) == 0) {
            return -1;
        }
    } else if (n < 0) {
        sz = uvm_dealloc(p->mm->pagetable, oldsz, newsz);
    }
    if (p->mm->heap_vma == NULL) {
        if (vma_map(p->mm, p->mm->start_brk, sz - p->mm->start_brk, PERM_READ | PERM_WRITE, VMA_HEAP) < 0) {
            panic("TODO: ERROR HANDLER");
        }
    }
    p->mm->brk = sz;
    p->mm->heap_vma->size = PGROUNDUP(sz) - p->mm->start_brk;
    return 0;
}

// Copy to either a user address, or kernel address,
// depending on usr_dst.
// Returns 0 on success, -1 on error.
int either_copy_out(int user_dst, uint64 dst, void *src, uint64 len) {
    struct proc *p = proc_current();
    if (user_dst) {
        return copy_out(p->mm->pagetable, dst, src, len);
    } else {
        memmove((char *) dst, src, len);
        return 0;
    }
}

// Copy from either a user address, or kernel address,
// depending on usr_src.
// Returns 0 on success, -1 on error.
int either_copy_in(void *dst, int user_src, uint64 src, uint64 len) {
    struct proc *p = proc_current();
    if (user_src) {
        return copy_in(p->mm->pagetable, dst, src, len);
    } else {
        memmove(dst, (char *) src, len);
        return 0;
    }
}

