            f->f_op = get_fileops[proc_current()->cwd.fs->fs_type]();
            release(&_ftable.lock);
            return f;
        }
    }
    release(&_ftable.lock);
    return 0;
}
/**
 * Allocates a file descriptor for the given file.
 *
 * @param f The file to allocate a file descriptor for.
 * @return The allocated file descriptor.
 */
int fd_alloc(struct file *f) {
    struct proc *p = proc_current();
    acquire(&p->tlock);
    for (int fd = 0; fd < p->max_ofile; fd++) {
        if (p->_ofile[fd] == 0) {
            p->_ofile[fd] = f;
            release(&p->tlock);
            return fd;
        }
    }
    release(&p->tlock);
    return -1;
}

void generic_fileclose(struct file *f) {
    struct file ff;

    acquire(&_ftable.lock);
    if (f->f_count < 1)
        panic("generic_fileclose");
    if (--f->f_count > 0) {
        release(&_ftable.lock);
        return;
    }
    ff = *f;
    f->f_count = 0;
    f->f_type = FD_NONE;
    release(&_ftable.lock);

    if (ff.f_type == FD_PIPE) {
        const int wrable = F_WRITEABLE(&ff);
        pipe_close(ff.f_data.f_pipe, wrable);
    } else if (ff.f_type == FD_REG || ff.f_type == FD_DEVICE) {
        struct file_vnode *fv = ff.f_data.f_vnode;
        if (fv->fs->fs_type == FAT32) {
            struct inode *f_inode = fv->data;
            f_inode->i_op->put(f_inode);
        } else if (fv->fs->fs_type == EXT4) {
            // TODO: it's ugly
            vfs_ext_fclose(&ff);
            if (ff.removed) {
                vfs_ext_rm(fv->path);
                ff.removed = 0;
            }
        } else if (fv->fs->fs_type == PROCFS) {
            procfs_fclose(&ff);
        }
        kfree(fv);
        ff.f_data.f_vnode = 0;
    }
}

