struct inode *find_inode(char *path, int dirfd, char *name) {
    ASSERT(path);
    struct inode *ip;
    struct proc *p = proc_current();
    if (*path == '/' || dirfd == AT_FDCWD) {
        // 绝对路径 || 相对于当前路径，忽略 dirfd
        ip = name == NULL ? namei(path) : namei_parent(path, name);
        if (ip == 0) {
            return 0;
        }
        return ip;
    }
    // path为相对于 dirfd目录的路径
    struct file *f;
    if (dirfd < 0 || dirfd >= NOFILE || (f = p->_ofile[dirfd]) == 0) {
        return 0;
    }
    struct file_vnode oldcwd = p->cwd;
    p->cwd = *f->f_data.f_vnode;
    ip = name == NULL ? namei(path) : namei_parent(path, name);
    if (ip == 0) {
        return 0;
    }
    p->cwd = oldcwd;

    return ip;
}

static char *skepelem(char *path, char *name) {
    while (*path == '/' || *path == '.')
        path++;
    if (*path == 0)
        return 0;
    const char *s = path;
    while (*path != '/' && *path != 0)
        path++;
    const int len = path - s;
    if (len >= PATH_LONG_MAX)
        memmove(name, s, PATH_LONG_MAX);
    else {
        memmove(name, s, len);
        name[len] = 0;
    }
    while (*path == '/')
        path++;
    return path;
}

static struct inode *inode_namex(char *path, const int nameeparent, char *name) {
    struct inode *ip = NULL, *next = NULL, *cwd = proc_current()->cwd.data;
    // ASSERT(cwd);
    // TODO BUG: cwd may be NULL
    if (*path == '/') {
        ASSERT(cwd->i_sb);
        ASSERT(cwd->i_sb->root);
        struct inode *root_ip = cwd->i_sb->root;
        ip = root_ip->i_op->dup(root_ip);
    } else if (strncmp(path, "..", 2) == 0) {
        ip = cwd->parent->i_op->dup(cwd->parent);
    } else {
        ip = cwd->i_op->dup(cwd);
    }

    while ((path = skepelem(path, name)) != 0) {
        ip->i_op->lock(ip);
        if (!ip->i_op->dir(ip)) {
            ip->i_op->unlock_put(ip);
            return 0;
        }
        if (nameeparent && *path == '\0') {
            ip->i_op->unlock(ip);
            return ip;
        }

        if (strncmp(name, "..", 2) == 0) {
            next = ip->i_op->dup(ip->parent);
        } else if (strncmp(name, ".", 1) == 0) {
            next = ip->i_op->dup(ip);
        } else if ((next = ip->i_op->dirlookup(ip, name, 0)) == 0) {
            ip->i_op->unlock_put(ip);
            return 0;
        }
        ip->i_op->unlock_put(ip);
        ip = next;
    }

    if (nameeparent) {
        ip->i_op->put(ip);
        return 0;
    }

    if (ip->i_op == NULL) {
        ASSERT(cwd->fs_type == FAT32);
        ip->i_op = get_inodeops[cwd->fs_type]();
    }

    return ip;
}

