int pipe_alloc(struct file **f0, struct file **f1) {
    struct pipe *pi;

    pi = 0;
    *f0 = *f1 = 0;
    if ((*f0 = file_alloc()) == 0 || (*f1 = file_alloc()) == 0)
        goto bad;
    if ((pi = (struct pipe *) kalloc()) == 0)
        goto bad;
    pi->readopen = 1;
    pi->writeopen = 1;
    pi->nwrite = 0;
    pi->nread = 0;
    init_lock(&pi->lock, "pipe");

    sem_init(&pi->read_sem, 0, "read_sem");
    sem_init(&pi->write_sem, 0, "write_sem");

    (*f0)->f_type = FD_PIPE;
    (*f0)->f_flags = O_RDONLY;
    (*f0)->f_data.f_pipe = pi;

    (*f1)->f_type = FD_PIPE;
    (*f1)->f_flags = O_WRONLY;
    (*f1)->f_data.f_pipe = pi;
    return 0;

bad:
    if (pi)
        kfree((char *) pi);
    if (*f0)
        generic_fileclose(*f0);
