        generic_fileclose(*f1);
    return -1;
}


void pipe_close(struct pipe *pi, int writable) {
    acquire(&pi->lock);
    if (writable) {
        pi->writeopen = 0;
        sem_v(&pi->read_sem);
    } else {
        pi->readopen = 0;
        sem_v(&pi->write_sem);
    }
    if (pi->readopen == 0 && pi->writeopen == 0) {
        release(&pi->lock);
        kfree((char *) pi);
    } else
        release(&pi->lock);
}

int pipe_write(struct pipe *pi, uint64 addr, int n) {
    int i = 0;
    struct proc *pr = proc_current();

    acquire(&pi->lock);
    while (i < n) {
        if (pi->readopen == 0 || proc_is_killed(pr)) {
            release(&pi->lock);
            return -1;
        }
        if (pi->nwrite == pi->nread + PIPESIZE) { // DOC: pipewrite-full
            sem_v(&pi->read_sem);

            release(&pi->lock);
            sem_p(&pi->write_sem);
            acquire(&pi->lock);
        } else {
            char ch;
            if (copy_in(pr->mm->pagetable, &ch, addr + i, 1) == -1)
                break;
            pi->data[pi->nwrite++ % PIPESIZE] = ch;
            i++;
        }
    }
    sem_v(&pi->read_sem);
    release(&pi->lock);

    return i;
}

int pipe_read(struct pipe *pi, uint64 addr, int n) {
    int i;
    struct proc *pr = proc_current();
    char ch;

    acquire(&pi->lock);
    while (pi->nread == pi->nwrite && pi->writeopen) { // DOC: pipe-empty
        if (proc_is_killed(pr)) {
            release(&pi->lock);
            return -1;
        }
        release(&pi->lock);
        sem_p(&pi->read_sem);
        acquire(&pi->lock);
    }
    for (i = 0; i < n; i++) { // DOC: piperead-copy
        if (pi->nread == pi->nwrite)
            break;
        ch = pi->data[pi->nread % PIPESIZE];
        if (copy_out(pr->mm->pagetable, addr + i, &ch, 1) == -1)
            break;
        ++pi->nread;
    }
    sem_v(&pi->write_sem);
    release(&pi->lock);
    return i;
}
int pipe_empty(struct pipe *p) {
    acquire(&p->lock);
    int ret = (p->nread == p->nwrite);
    release(&p->lock);
    return ret;
}

int pipe_full(struct pipe *p) {
    acquire(&p->lock);
    int ret = ((p->nread + PIPESIZE) == p->nwrite);
    release(&p->lock);
    return ret;
}

