// Read a shared 32-bit value without holding a lock
int atomic_read4(const int *addr) {
    int val;
    __atomic_load(addr, &val, __ATOMIC_SEQ_CST);
    return val;
}
// Acquire the lock.
// Loops (spins) until the lock is acquired.
void do_acquire(struct spinlock *lk) {
    push_off(); // disable interrupts to avoid deadlock.
    if (holding(lk)) {
        printf("%s\n", lk->name);
        panic("acquire");
    }

    while (__sync_lock_test_and_set(&lk->locked, 1) != 0)
        ;
    __sync_synchronize();
    lk->cpu = mycpu();
}

// Release the lock.
void do_release(struct spinlock *lk) {
    if (!holding(lk)) {
        printf("%s\n", lk->name);
        panic("release");
    }
    lk->cpu = 0;
    __sync_synchronize();
    __sync_lock_release(&lk->locked);

    pop_off();
}

void init_lock(struct spinlock *lk, char *name) {
    lk->locked = 0;
    lk->cpu = 0;
    strncpy(lk->name, name, strlen(name));
}
// if need to debug, you can add the following code
void wrap_acquire(char *file, int line, struct spinlock *lock) { do_acquire(lock); }
// if need to debug, you can add the following code
void wrap_release(char *file, int line, struct spinlock *lock) { do_release(lock); }

int holding(struct spinlock *lk) {
    int r;
    r = (lk->locked && lk->cpu == mycpu());
    return r;
}

void push_off(void) {
    int old = intr_get();
    intr_off();
    if (mycpu()->noff == 0)
        mycpu()->intena = old;
    mycpu()->noff += 1;
}

void pop_off(void) {
    struct thread_cpu *c = mycpu();
    if (intr_get())
        panic("pop_off - interruptible");
    if (c->noff < 1)
        panic("pop_off");
    c->noff -= 1;
    if (c->noff == 0 && c->intena)
        intr_on();
}

