void sem_init(sem *S, int value, char *name) {
    S->value = value;
    S->wakeup = 0;
    init_lock(&S->sem_lock, name);
    cond_init(&S->sem_cond, name);
}

void sem_p(sem *S) {
    acquire(&S->sem_lock);
    S->value--;
    if (S->value < 0) {
        do {
            cond_wait(&S->sem_cond, &S->sem_lock);
        } while (S->wakeup == 0);
        S->wakeup--;
    }
    release(&S->sem_lock);
}

void sem_v(sem *S) {
    acquire(&S->sem_lock);
    S->value++;
    if (S->value <= 0) {
        S->wakeup++;
        cond_signal(&S->sem_cond);
    }
    release(&S->sem_lock);
}

