void cond_init(struct cond *cond, char *name) { Queue_init(&cond->waiting_queue, name, TCB_WAIT_QUEUE); }

// wait
void cond_wait(struct cond *cond, struct spinlock *mutex) {
    struct tcb *t = thread_current();

    acquire(&t->lock);

    TCB_Q_changeState(t, TCB_SLEEPING);

    Queue_push_back(&cond->waiting_queue, t);

    t->wait_chan_entry = &cond->waiting_queue;

    release(mutex);

    thread_sched();

    // for signal
    int killed = t->killed;
    release(&t->lock);
    if (killed) {
        do_exit(-1);
    }

    // Reacquire original lock.
    acquire(mutex);
}

