/**
 * @brief fetch the raw argument at index n from the current process.
 * @param addr
 * @param buf
 * @param max
 * @return
 */
static uint64 arg_raw(int n) {
    // struct proc *p = proc_current();
    struct tcb *t = thread_current();
    switch (n) {
        case 0:
            return t->trapframe->a0;
        case 1:
            return t->trapframe->a1;
        case 2:
            return t->trapframe->a2;
        case 3:
            return t->trapframe->a3;
        case 4:
            return t->trapframe->a4;
        case 5:
            return t->trapframe->a5;
        default:
            break;
    }
    panic("argraw");
    return -1;
}

