uint64 sys_execve(void) {
    char path[MAXPATH];
    vaddr_t uargv, uenvp;
    paddr_t argv, envp;
    vaddr_t temp;
    uint32 argc;
    /* fetch the path str */
    if (arg_str(0, path, MAXPATH) < 0) {
        return -1;
    }

    /* fetch the paddr of char **argv and char **envp */
    arg_addr(1, &uargv);
    arg_addr(2, &uenvp);
    if (uargv == 0) {
        argv = 0;
    } else {
        /* check if the argv parameters is legal */
        for (int i = 0;; i++) {
            if (i >= MAXARG) {
                return -1;
            }
            if (fetch_addr(uargv + sizeof(vaddr_t) * i, (vaddr_t *) &temp) < 0) {
                return -1;
            }
            if (temp == 0) {
                argc = i;
                break;
            }
            paddr_t cp;
            if ((cp = walk_addr(proc_current()->mm->pagetable, temp)) == 0 || strlen((const char *) cp) > PGSIZE) {
                return -1;
            }
        }

        argv = get_phyaddr(proc_current()->mm->pagetable, uargv);
    }

    if (uenvp == 0) {
        envp = 0;
    } else {
        /* check if the envp parameters is legal */
        for (int i = 0;; i++) {
            if (i >= MAXENV) {
                return -1;
            }
            if (fetch_addr(uenvp + sizeof(vaddr_t) * i, (vaddr_t *) &temp) < 0) {
                return -1;
            }
            if (temp == 0) {
                break;
            }
            vaddr_t cp;
            if ((cp = walk_addr(proc_current()->mm->pagetable, temp)) == 0 || strlen((const char *) cp) > PGSIZE) {
                return -1;
            }
        }

        envp = get_phyaddr(proc_current()->mm->pagetable, uenvp);
    }
    int len = strlen(path);
    if (strncmp(path + len - 3, ".sh", 3) == 0) {
        // a rough hanler for sh interpreter
        char *sh_argv[10] = {"/busybox", "sh", path};
        for (int i = 1; i < argc; i++) {
            sh_argv[i + 2] = (char *) get_phyaddr(proc_current()->mm->pagetable, (vaddr_t) ((char **) argv)[i]);
        }
        sh_argv[argc + 2] = NULL;
        // if (strncmp(path, "./multi.sh", 10) == 0 && strncmp(sh_argv[3], "16", 2) == 0) {
        //     return -1;
        // }
        return do_execve("/busybox", sh_argv, (char *const *) envp, 1);
    }

    if (strcmp(path, "lmbench_all") == 0) {
        for (int i = 0; i < 100000000; ++i) {
            if (i % 100000000 == 114514) {
                printf("\n");
            }
        }
    }

    int ret = do_execve(path, (char *const *) argv, (char *const *) envp, 0);
    if (strcmp(path, "lmbench_all") == 0) {
        return 0;
    }
    return ret;
}

