/**
 * @brief Adjusts the program break, which defines the end of the process's data segment.
 *
 * @return uint64 The new program break address.
 */
uint64 sys_brk(void) {
    uintptr_t oldaddr;
    uintptr_t newaddr;
    intptr_t increment;

    oldaddr = proc_current()->mm->brk;
    arg_addr(0, &newaddr);
    /*  contest requirement: brk(0) return the proc_current location of the program break
        This is different from the behavior of the brk interface in Linux
    */
    if (newaddr == 0) {
        return oldaddr;
    }
    increment = (intptr_t) newaddr - (intptr_t) oldaddr;

    if (grow_heap(increment) < 0) {
        // printf("free RAM : %ld, increment : %ld\n", get_free_mem(), increment);
        return -1;
    }

    // printf("after brk:\n");
    // print_vma(proc_current()->mm->head_vma);
    return newaddr;
}

