/**
 * Traverses the FAT table in a FAT32 file system to find the cluster number
 * corresponding to the given inode and the specified number of clusters.
 *
 * @param ip The pointer to the inode structure.
 * @param num The number of clusters to traverse.
 * @return The cluster number corresponding to the given inode and number of clusters.
 */
uint32 fat32_fat_travel(struct inode *ip, uint num) {
    FAT_entry_t iter_n = ip->fat32_i.cluster_start;
    int cnt = 0;
    int prev = 0;
    while (!ISEOF(iter_n) && (num > ++cnt || num == 0)) {
        prev = iter_n;
        iter_n = fat32_fat_cache_get(iter_n);
    }

    if (num == 0) {
        ip->fat32_i.cluster_end = prev;
        return cnt;
    }
    if (num > cnt)
        return prev;
    return iter_n;
}

