    if (ip->fat32_i.fname[0] != '/') {
        fat32_get_absolute_path(ip->parent, buf);
    }
    const size_t n0 = strlen(buf);
    const size_t n1 = strlen(ip->fat32_i.fname);
    strncpy(buf + n0, ip->fat32_i.fname, n1);
    if (ip->fat32_i.fname[0] != '/') {
        strncpy(buf + n0 + n1, "/", 2);
