int procfs_read(struct file *f, int user_src, const uint64 addr, int n) {
    size_t bytesread = 0;

    char *kbuf = NULL;
    if (user_src) {
        kbuf = (char *) kzalloc(n + 1);
        if (kbuf == NULL) {
            return -ENOMEM;
        }
    } else {
        kbuf = (char *) addr;
    }

    if (f->f_pos == 0) {
        if (strcmp(f->f_data.f_vnode->path, "/proc/stat") == 0) {
            bytesread = serialize_stat(kbuf, n);
        } else if (strcmp(f->f_data.f_vnode->path, "/proc/meminfo") == 0) {
            bytesread = serialize_meminfo(kbuf, n);
        } else if (strcmp(f->f_data.f_vnode->path, "/proc/mounts") == 0) {
            bytesread = serialize_mounts(kbuf, n);
        } else if (strcmp(f->f_data.f_vnode->path, "/proc/sys/kernel/pid_max") == 0) {
            bytesread = snprintf(kbuf, n, "%d\n", PID_MAX_DEFAULT);
        } else { /* /proc/{pid} */
            pid_t pid;
            if ((pid = get_pid_from_path(f->f_data.f_vnode->path)) != -1) {
                const char *op = get_op_from_path(f->f_data.f_vnode->path);
                bytesread = procfs_proc_read(pid, op, (uint64) kbuf, n);
            } else {
                bytesread = 0;
            }
        }
    }

    f->f_pos += bytesread;

    if (user_src) {
        if (copy_out(proc_current()->mm->pagetable, addr, kbuf, bytesread) != 0) {
            kfree(kbuf);
            return -EFAULT;
        }
        kfree(kbuf);
    } else {
        memmove((char *) addr, kbuf, bytesread);
    }

    return bytesread;
}

int procfs_write(struct file *f, int user_src, const uint64 addr, int n) {
    size_t byteswrite = 0;

    printf("procfs_write: %d\n", n);

    char *kbuf = NULL;
    if (user_src) {
        kbuf = (char *) kzalloc(n + 1);
        if (kbuf == NULL) {
            return -ENOMEM;
        }
    } else {
        kbuf = (char *) addr;
    }

    if (user_src) {
        if (copy_in(proc_current()->mm->pagetable, kbuf, addr, n) != 0) {
            kfree(kbuf);
            return -EFAULT;
        }
        kfree(kbuf);
    } else {
        memmove((char *) addr, kbuf, byteswrite);
    }

    pid_t pid;
    if ((pid = get_pid_from_path(f->f_data.f_vnode->path)) != -1) { /* /proc/{pid} */
        const char *op = get_op_from_path(f->f_data.f_vnode->path);
        byteswrite = procfs_proc_write(pid, op, (uint64) kbuf, n);
    } else {
        return -1; /* other file not supported */
    }

    return byteswrite;
}

