#define TICK_GRANULARITY 10L // ms
#define SEC2TICK(sec) ((sec) * 1000 / TICK_GRANULARITY)
#define MS2TICK(ms) ((ms) / TICK_GRANULARITY)
#define US2TICK(us) ((us) * TICK_GRANULARITY / 1000)
#define NS2TICK(ns) ((ns) / 1000 / 1000 / TICK_GRANULARITY)
static inline uint64 ts2ticks(struct timespec *ts) { return !ts ? 0 : NS2TICK(ts->tv_nsec) + SEC2TICK(ts->tv_sec); }

extern struct cond cond_ticks;

uint64 sys_ppoll(void) {
    uint64 pfdaddr;
    int nfds;
    uint64 tsaddr;
    uint64 sigmaskaddr;
    struct proc *p = proc_current();

    arg_addr(0, &pfdaddr);
    arg_int(1, &nfds);
    arg_addr(2, &tsaddr);
    arg_addr(3, &sigmaskaddr);

    // ASSERT(nfds == 1);
    printf("nfds: %d\n", nfds);

    struct pollfd pfd;

    if (copy_in(p->mm->pagetable, (char *) &pfd, pfdaddr, sizeof(pfd)) < 0)
        return -1;

    ASSERT(pfd.fd == 0);
    // ASSERT(pfd.events == POLLIN);
    printf("fd: %d, events: %d\n", pfd.fd, pfd.events);

    struct file *f = p->_ofile[pfd.fd];

    struct timespec ts;
    if (tsaddr && copy_in(p->mm->pagetable, (char *) &ts, tsaddr, sizeof(struct timespec)) < 0)
        return -1;

    uint64 timeout = tsaddr ? ts2ticks(&ts) : -1;

    while (1) {
        switch (f->f_type) {
            case FD_PIPE:
                return 1;
            case FD_DEVICE:
                if (console_ready()) {
                    if (timeout == 0)
                        return 0;
                }
                break;
            default:
                panic("error");
        }

        if (timeout == -1)
            continue;

        if (timeout) {
            acquire(&cond_ticks.waiting_queue.lock);
            cond_wait(&cond_ticks, &cond_ticks.waiting_queue.lock);
            release(&cond_ticks.waiting_queue.lock);
            timeout--;
        } else {
            break;
        }
    }

    if (timeout == 0)
        return 0;

    pfd.revents = pfd.events;
    if (copy_out(p->mm->pagetable, pfdaddr, (char *) &pfd, sizeof(pfd)) < 0)
        return -1;

    return 1;
}

