/*
                    Sv39 Virtual Address
+--------+-------------+-------------+-------------+--------+
| (zero) | level-2 idx | level-1 idx | level-0 idx | offset |
| 63..39 |   38..30    |   29..21    |    20..12   |  11..0 |
+--------+-------------+-------------+-------------+--------+
*/
// Physical memory layout

// qemu -machine virt is set up like this,
// based on qemu's hw/riscv/virt.c:
//
// 00001000 -- boot ROM, provided by qemu
// 02000000 -- CLINT
// 0C000000 -- PLIC
// 10000000 -- uart0
// 10001000 -- virtio disk
// 80000000 -- boot ROM jumps here in machine mode
//             -kernel loads the kernel here
// unused RAM after 80000000.

// the kernel uses physical memory thus:
// 80000000 -- entry.S, then kernel text and data
// end -- start of kernel page allocation area
// PHYSTOP -- end RAM used by the kernel

// qemu puts UART registers here in physical memory.
#define UART0 0x10000000L
#ifdef QEMU
#define UART0_IRQ 10
#elif defined(VISIONFIVE)
#define UART0_IRQ 32
#endif

#define SD_BASE 0x16020000

#ifdef QEMU
// virtio mmio interface
#define VIRTIO0 0x10001000
#endif

#define VIRTIO0_IRQ 1

// core local interruptor (CLINT), which contains the timer.
#define CLINT 0x2000000L
// #define CLINT_MTIMECMP(hartid) (CLINT + 0x4000 + 8 * (hartid))
#define CLINT_MTIME (CLINT + 0xBFF8) // cycles since boot.
#ifdef QEMU
#define CLINT_INTERVAL 1000000 // cycles; about 1/10th second in qemu.
#elif defined(VISIONFIVE)
#define CLINT_INTERVAL 800000 // CLK_FREQ / ticks_per_second
#endif
// qemu puts platform-level interrupt controller (PLIC) here.
#define PLIC 0x0c000000L
#define PLIC_PRIORITY (PLIC + 0x0)
#define PLIC_PENDING (PLIC + 0x1000)
#define PLIC_MENABLE(hart) (PLIC + 0x2000 + (hart) * 0x100)
#define PLIC_SENABLE(hart) (PLIC + 0x2080 + (hart) * 0x100)
#define PLIC_MPRIORITY(hart) (PLIC + 0x200000 + (hart) * 0x2000)
#define PLIC_SPRIORITY(hart) (PLIC + 0x201000 + (hart) * 0x2000)
#define PLIC_MCLAIM(hart) (PLIC + 0x200004 + (hart) * 0x2000)
#define PLIC_SCLAIM(hart) (PLIC + 0x201004 + (hart) * 0x2000)

// the kernel expects there to be RAM
// for use by the kernel and user pages
// from physical address 0x80000000 to PHYSTOP.
#define KERNBASE 0x80200000L
#ifdef QEMU
#define PHYSTOP (0x80000000L + 0xc0000000ULL)
#elif defined(VISIONFIVE)
// 0x80000000 + 3GB
#define PHYSTOP (0x80000000ULL + 0xc0000000ULL)
#endif

// map the trampoline page to the highest address,
// in both user and kernel space.
#define TRAMPOLINE (MAXVA - PGSIZE)

// map kernel stacks beneath the trampoline,
// each surrounded by invalid guard pages.
#define KSTACK(p) (TRAMPOLINE - ((p) + 1) * 2 * PGSIZE)

#define LDSO 0x40000000

// User memory layout.
// Address zero first:
//   text
//   original data and bss
//   fixed-size stack
//   expandable heap
//   ...
//   TRAPFRAME (p->trapframe, used by the trampoline)
//   SIGRETURN
//   TRAMPOLINE (the same page as in the kernel)
#define SIGRETURN (TRAMPOLINE - PGSIZE)
#define TRAPFRAME (SIGRETURN - PGSIZE)
#define THREAD_TRAPFRAME(id) (TRAPFRAME - (id) * PGSIZE)

#define USTACK_PAGE 65
#define USTACK (MAXVA - 512 * 10 * PGSIZE - USTACK_PAGE * PGSIZE)
#define USTACK_GURAD_PAGE (USTACK - PGSIZE)
#define USTACK_TOP (USTACK + USTACK_PAGE * PGSIZE)
#define TOTAL_MEM (PHYSTOP - START_MEM)
#define FREE_MEM (get_free_mem())
#define USED_MEM (FREE_MEM - TOTAL_MEM)
#define FREE_RATE(rate) (DIV_ROUND_UP(FREE_MEM, rate))

#define wmb() __asm__ __volatile__("fence w,o" : : : "memory")
#define rmb() __asm__ __volatile__("fence i,r" : : : "memory")


