 *
 * @param ip inode
 * @param p_entry page list
 * @param rw read or write
 * @param cnt page count
 * @param alloc alloc or not
 */
void rw_pages(struct inode *ip, uint64 src, uint64 index, int rw, uint64 cnt, int alloc) {
    struct bio bio_cur;

    // init bio
    INIT_LIST_HEAD(&bio_cur.list_entry);
    bio_cur.bi_rw = rw;
    bio_cur.bi_bdev = ip->i_dev;

    // fill bio with bio_vec
    block_full_pages(ip, &bio_cur, src, index, cnt, alloc);

    // submit bio
    if (!list_empty(&bio_cur.list_entry)) {
        submit_bio(&bio_cur, 1); // free bio_vec of bio
    }
}

// read/write more than one page using page batch
void rw_pages_batch(struct inode *ip, struct page_entry *p_entry, int rw, int alloc) {
    struct page_item *p_cur_out = NULL;
    int batch_size = 1;

    // out : we don't use list_for_each_entry_safe in order to change p_cur_out in inner
    list_for_each_entry(p_cur_out, &p_entry->entry, list) {
        struct page_item *p_cur_in = NULL;
        struct page_item *p_nxt_in = NULL;

        struct page_item *p_tmp_head_in = p_cur_out; // !!!
        batch_size = 1;
        // inner :
        list_for_each_entry_safe_condition(p_cur_in, p_nxt_in, &p_tmp_head_in->list, list,
                                           &p_cur_in->list != &p_entry->entry) {
            if (PAGE_ADJACENT(p_cur_out, p_cur_in)) {
                p_cur_out = p_cur_in; // !!!!!!!!!
                batch_size++;
            } else {
                break;
            }
        }
        rw_pages(ip, p_tmp_head_in->pa, p_tmp_head_in->index, rw, batch_size,
                 alloc); // don't write batch_size as batch_size * PGSIZE
    }

    // must remember to free page list
    page_list_free(p_entry);
}

void page_list_free(struct page_entry *p_entry) {
    struct page_item *p_cur = NULL;
    struct page_item *p_tmp = NULL;
    list_for_each_entry_safe(p_cur, p_tmp, &p_entry->entry, list) { kfree(p_cur); }
}

// read pages
// index : page start index
// cnt : page count
// read_from_disk : need to read from disk ??
// return : pa of the first page
uint64 mpage_readpages(struct inode *ip, uint64 index, uint64 cnt, int read_from_disk, int alloc) {
    struct page_entry p_entry;
    struct address_space *mapping = ip->i_mapping;
    ASSERT(cnt > 0);
    INIT_LIST_HEAD(&p_entry.entry); // !!!
    p_entry.n_pages = 0; // !!!!!! bug

    // the process below may be some complex
    // [start_idx, end_idx) is valid
    // we use two pointer to filter valid interval
    uint64 first_pa = 0;
    uint64 pa = 0;
    for (uint64 start_idx = 0; start_idx < cnt;) {
        if (!find_get_page_atomic(mapping, index + start_idx, 0)) {
            // not find it, not holding lock
            uint64 end_idx = start_idx + 1;
            while (end_idx < cnt) {
                if (find_get_page_atomic(mapping, index + end_idx, 0)) {
                    // find it, not holding lock
                    break;
                }
                end_idx++;
            }

            // allocpages:
            if ((pa = (uint64) kzalloc(PGSIZE * (end_idx - start_idx))) == 0) {
                printfRed("end_idx : %d, start_idx : %d\n", end_idx, start_idx);
                panic("mpage_readpages, pa, : no enough memory\n");
            }

            if (first_pa == 0) {
                first_pa = pa; // !!!
            }

            struct page_item *p_item = NULL;
            for (int z = start_idx; z < end_idx; z++) {
                uint64 pa_tmp = pa + (z - start_idx) * PGSIZE;
                uint64 index_tmp = index + z;
                struct page *page = pa_to_page(pa_tmp);
                add_to_page_cache_atomic(page, mapping, index_tmp); // don't forget it

                if (cnt == 1 && read_from_disk == 0) {
                    return first_pa; // !!!
                }

                // page list item :
                if ((p_item = (struct page_item *) kzalloc(sizeof(struct page_item))) == NULL) {
                    panic("mpage_readpages, p_item, : no enough memory\n");
                }
                // printfMAGENTA("mpage_readpages: page_item alloc, mm-- : %d pages\n", get_free_mem() / 4096);
                p_item->index = index_tmp; // !!!
                p_item->pa = pa_tmp; // !!!

                INIT_LIST_HEAD(&p_item->list);

                // join p_item into p_entry
                list_add_tail(&p_item->list, &p_entry.entry);
                p_entry.n_pages++;
            }

            start_idx = end_idx + 1;
        } else {
            if (start_idx == 0) {
                panic("mpage_readpages ,start idx : error\n");
            }
            start_idx++;
        }
    }

    if (read_from_disk)
        // read pages using page list
        rw_pages_batch(ip, &p_entry, DISK_READ, alloc);

    return first_pa;
}

// write pages
void mpage_writepage(struct inode *ip, int alloc) {
    struct address_space *mapping = ip->i_mapping;
    acquire(&ip->tree_lock);
    if (mapping == NULL) {
        panic("mapping is NULL\n");
    }
    if (mapping->page_tree.height == 0 && mapping->page_tree.rnode == NULL) {
        release(&ip->tree_lock);
        return;
    }

    struct page_entry p_entry;
    INIT_LIST_HEAD(&p_entry.entry); // !!!
    p_entry.n_pages = 0; // !!! bug

    int ret = radix_tree_general_gang_lookup_elements(&(mapping->page_tree), &p_entry, page_list_add, 0,
                                                      maxitems_invald, PAGECACHE_TAG_DIRTY);
    ASSERT(ret > 0);
    if (mapping->page_tree.height == 0 && ret != 1) {
        panic("mpage_writepage : error\n");
    }
    release(&ip->tree_lock);

    // write pages using page list
    rw_pages_batch(ip, &p_entry, DISK_WRITE, alloc);
}

// add page item into page list
void page_list_add(void *entry, void *item, uint64 index, void *node) {
    struct page_entry *p_entry = (struct page_entry *) entry;
    struct page_item *p_item = NULL;
    if ((p_item = (struct page_item *) kzalloc(sizeof(struct page_item))) == NULL) {
        panic("mpage_readpages, page_list_add, : no enough memory\n");
    }

    // printfMAGENTA("page_list_add(page cache write back), mm ++: %d pages\n", get_free_mem() / 4096);

    // p_item
    struct page *page = (struct page *) item;
    p_item->index = index;
    p_item->pa = page_to_pa(page);

    INIT_LIST_HEAD(&p_item->list);

    // join p_item into p_entry
    list_add_tail(&p_item->list, &p_entry->entry);
    // bug like this :     list_add_tail&p_entry->entry, &p_item->list);
    p_entry->n_pages++;
}

#include "fs/vfs/filemap.h"
#include "fs/vfs/inode_cache.h"
#include "fs/vfs/mpage.h"
#include "kernel/trap.h"
#include "mm/allocator.h"

// add
int add_to_page_cache_atomic(struct page *page, struct address_space *mapping, uint64 index) {
    page->mapping = mapping;
    page->pagecache_idx = index;

    int error = radix_tree_insert(&mapping->page_tree, index, page);
    if (likely(!error)) {
        mapping->nrpages++;
    } else {
        panic("add_to_page_cache : error\n");
    }
    return error;
}

// find
struct page *find_get_page_atomic(struct address_space *mapping, uint64 index, int lock) {

    struct page *page = radix_tree_lookup_node(&mapping->page_tree, index);

    if (page) {
        if (lock)
            acquire(&page->lock);
    }

    return page;
}

// read ahead
uint64 max_sane_readahead(uint64 nr, uint64 read_ahead, uint64 tot_nr) {
    return MIN(MIN(PGROUNDUP(nr) / PGSIZE + read_ahead, DIV_ROUND_UP(FREE_RATE(READ_AHEAD_RATE), PGSIZE)),
               PGROUNDUP(tot_nr) / PGSIZE);
    // don't forget /PGSIZE
}

// read using mapping
ssize_t do_generic_read(struct address_space *mapping, int user_dst, uint64 dst, uint off, uint n) {

    struct inode *ip = mapping->host;
    ASSERT(ip->i_size > 0);

    uint64 index = off >> PGSHIFT; // page number
    uint64 offset = PGMASK(off); // offset in a page
    const uint64 end_index = (ip->i_size - 1) >> PGSHIFT;
    const uint32 isize = ip->i_size;
    uint64 read_sane_cnt = 0; // 1, 2, 3, ...

    uint64 pa;

    ssize_t retval = 0;

    sem_p(&ip->i_read_lock);
    while (1) {

        /* nr is the maximum number of bytes to copy from this page */
        uint64 nr = PGSIZE;
        if (index >= end_index) {
            if (index > end_index)
                goto out;
            // if index == end_index
            nr = (PGMASK((isize - 1))) + 1;
            // it is larger than offset of off
            if (nr <= offset) {
                panic("not tested\n");
                goto out;
            }
        }
        nr = nr - offset;
        /* Find the page */
        struct page *page = find_get_page_atomic(mapping, index, 0); // not acquire the lock of page
        if (page == NULL) {
            read_sane_cnt = max_sane_readahead(n - retval, mapping->readahead_cnt, isize - (off + retval));
            mapping->readahead_end = index + read_sane_cnt - 1; // !!!
            if (read_sane_cnt <= 0) {
                goto out;
            }

            pa = mpage_readpages(ip, index, read_sane_cnt, 1, 0); // must read from disk, can't allocate new clusters

            // change the read_ahead_cnt dynamically
            if (index > (mapping->last_idx)) {
                int ahead_tmp = mapping->readahead_end + mapping->readahead_cnt;
                if (ahead_tmp <= end_index) {
                    if (mapping->readahead_cnt < READ_AHEAD_PAGE_MAX_CNT) {
                        CHANGE_READ_AHEAD(mapping); // exponential growth with base 2
                    } else {
                        mapping->readahead_cnt += 1; // linear growth with 1
                    }
                }
            } else {
                // not increase, set cnt to zero
                mapping->readahead_cnt = 0;
            }
            mapping->last_idx = index;
        } else {
            pa = page_to_pa(page);
        }

        // similar to fat32_inode_read
        // it is illegal to read beyond isize!!! (maybe it is reasonable to fill zero)
        const uint64 len = MIN(MIN(n - retval, nr), isize - offset);

        if (either_copy_out(user_dst, dst, (void *) (pa + offset), len) == -1) {
            retval = -1;
            goto out;
        }

        // off、retval、src
        // unit is byte
        off += len;
        retval += len;
        dst += len;

        if (retval == n) {
            break; // !!!
        }

        // index and offset
        // page_no + page_offset
        index = (off >> PGSHIFT);
        offset = PGMASK(off);
    }

out:
    sem_v(&ip->i_read_lock);
    return retval;
}

// write using mapping
ssize_t do_generic_write(struct address_space *mapping, int user_src, uint64 src, uint off, uint n) {
    struct inode *ip = mapping->host;
    ASSERT(n > 0);
    uint64 index = off >> PGSHIFT; // page number
    uint64 offset = PGMASK(off); // offset in a page
    uint64 pa;

    const uint64 isize_offset = ip->i_size % PGSIZE;

    ssize_t retval = 0;

    // printf("write begin : \n");
    sem_p(&ip->i_read_lock);
    while (1) {

        /* nr is the maximum number of bytes to copy from this page */
        const uint64 nr = PGSIZE - offset;
        struct page *page = find_get_page_atomic(mapping, index, 0); // not acquire lock
        // write_cnt++;
        if (page == NULL) {
            int read_from_disk = -1;

            if (WRITE_FULL_PAGE(n - retval) || OUT_FILE(offset, isize_offset)) {
                // need to read page in disk
                read_from_disk = 1;
            } else {
                read_from_disk = 0;
            }
            pa = mpage_readpages(ip, index, 1, read_from_disk, 1); // just read one page, allocate clusters if necessary
            page = pa_to_page(pa);
        } else {
            pa = page_to_pa(page);
        }

        // similar to fat32_inode_read
        const uint64 len = MIN(n - retval, nr);
        if (either_copy_in((void *) (pa + offset), user_src, src, len) == -1) {
            // panic("do_generic_file_write : copyin error\n");
            retval = -1;
            goto out;
        }

        // set page dirty
        acquire(&mapping->host->tree_lock);
        radix_tree_tag_set(&mapping->page_tree, index, PAGECACHE_TAG_DIRTY);
        release(&mapping->host->tree_lock);


        // off、retval、src
        // unit is byte
        off += len;
        retval += len;
        src += len;

        if (retval == n) {
            break; // !!!
        }

        // index and offset
        // page_no + page_offset
        index = off >> PGSHIFT;
        offset = PGMASK(off);
    }


out:
    sem_v(&ip->i_read_lock);
    return retval;
}

#include "atomic/spinlock.h"
#include "fs/vfs/mpage.h"


int sync_inode(struct inode *ip) {
    acquire(&ip->i_lock);
    if (ip->i_writeback) {
        release(&ip->i_lock);
        return -1;
    }
    ip->i_writeback = 1;
    release(&ip->i_lock);

    // page write back (all)
    mpage_writepage(ip, 1); // allocate if necessary

    // update fcb in parent
    if (ip->dirty_in_parent) {
        fat32_inode_update(ip);
    }

    return 0;
}

void writeback_inodes(uint64 nr_to_write) {
    // nr_to_write is not important
    struct inode *ip_cur = NULL;
    struct inode *ip_tmp = NULL;

    acquire(&fat32_sb.dirty_lock);
    list_for_each_entry_safe(ip_cur, ip_tmp, &fat32_sb.s_dirty_inodes, dirty_list) {
        release(&fat32_sb.dirty_lock);

        sem_p(&ip_cur->i_sem); // important ??? maybe
        int ret = sync_inode(ip_cur);
        sem_v(&ip_cur->i_sem);

        acquire(&fat32_sb.dirty_lock);
        if (ret == 0) {
            list_del_reinit(&ip_cur->dirty_list);
            ip_cur->i_writeback = 0;
        }
    }
    release(&fat32_sb.dirty_lock);
}

# cabbageOS 内核技术分析报告

## 1. 分析范围与方法

### 1.1 分析内容

本报告基于对 cabbageOS 内核项目的完整源码审查，涵盖以下方面：

- **源码结构分析**：遍历整个仓库的目录结构、文件组织和模块划分
- **核心子系统实现**：深入分析内存管理、进程/线程管理、文件系统、IPC、同步机制、驱动、系统调用等子系统的实现细节
- **汇编层分析**：检查启动代码、上下文切换、中断/异常处理、用户态/内核态切换等底层实现
- **构建系统分析**：审查 CMake 配置、Makefile、工具链配置和镜像制作流程
- **平台支持分析**：分析 QEMU 和 VisionFive2 两个平台的适配代码
- **依赖库分析**：检查 Rust 实现的 virtio-drivers 和 sdcard 驱动集成方式

### 1.2 测试情况

**未进行运行时测试**，原因如下：

1. **构建依赖缺失**：项目需要 `sudo mount` 权限来制作文件系统镜像，当前环境不支持
2. **镜像制作流程复杂**：需要先执行 `make-image` 生成文件系统镜像，该过程涉及 `mkfs.ext4`/`mkfs.vfat` 和 `mount`/`umount` 操作
3. **Rust 依赖编译**：VisionFive2 平台需要编译 Rust 实现的 sdcard 驱动，增加构建复杂度
4. **测试用例依赖外部资源**：`tests/oscomp` 和 `tests/final` 目录包含竞赛测试用例，需要特定的运行环境

因此，本报告的分析完全基于静态代码审查。

